noncompliant:
struct Flags {
    unsigned int flag1 : 1;  // Noncompliant: bit field
    unsigned int flag2 : 1;  // Noncompliant: bit field
    unsigned int value : 6;  // Noncompliant: bit field
};

struct Register {
    unsigned char enable : 1;     // Noncompliant: bit field
    unsigned char mode : 3;       // Noncompliant: bit field
    unsigned char reserved : 4;   // Noncompliant: bit field
};

compliant:
struct Flags {
    bool flag1;        // Compliant: explicit bool
    bool flag2;        // Compliant: explicit bool
    unsigned int value; // Compliant: full integer
};

// Alternative: use bit manipulation with constants
const unsigned int FLAG1_MASK = 0x01;
const unsigned int FLAG2_MASK = 0x02;
const unsigned int VALUE_MASK = 0xFC;

struct Register {
    unsigned char data;  // Compliant: use bit operations

    bool getEnable() const { return data & 0x01; }
    void setEnable(bool enable) { 
        data = enable ? (data | 0x01) : (data & ~0x01); 
    }
};
